const formatEffectsString = (effectsString) => {
    if (!effectsString || typeof effectsString !== 'string') return null;

    const effectdescriptions = effectsString.split(';').map(effectStr => {
        const [type, dataPart] = effectStr.split(/:(.*)/s);
        if (!type || !dataPart) return null;

        const data = parseKeyValueString(dataPart);
        const targetMappings = {
            'all_allies': 'cho cả đội',
            'all_enemies': 'lên toàn bộ kẻ địch',
            'self': 'lên bản thân',
            'single_ally': 'lên một đồng minh',
            'single_enemy': 'lên một kẻ địch',
        };
        const targetText = targetMappings[data.target] || '';

        switch (type.trim()) {
            case 'HEAL': {
                const formula = data.formula || '';
                if (formula.includes('MAX_HP')) {
                    const percentage = parseFloat(formula.split('*')[1]) * 100;
                    return `Hồi ${percentage}% HP tối đa ${targetText}`.trim();
                }
                const fixedMatch = formula.match(/FIXED:(\d+)/);
                if (fixedMatch && fixedMatch[1]) {
                    const amount = fixedMatch[1];
                    return `Hồi ${amount} HP ${targetText}`.trim();
                }
                return `Hồi phục sinh lực ${targetText}`.trim();
            }
            case 'DAMAGE': {
                 const formula = data.formula || '';
                 const fixedMatch = formula.match(/FIXED:(\d+)/);
                 if (fixedMatch && fixedMatch[1]) {
                    const amount = fixedMatch[1];
                    const isTrueDamage = data.true_damage === 'true';
                    return `Gây ${amount} sát thương ${isTrueDamage ? 'chuẩn' : ''} ${targetText}`.trim();
                }
                 return `Gây sát thương ${targetText}`.trim();
            }
            case 'APPLY_DYNAMIC_STATUS': {
                const duration = data.duration;
                const changes = data.stat_changes || '';
                const name = data.name || 'Hiệu ứng';
                
                const statMappings = {
                    ATK_PERCENT: '% Tấn Công', DEF_PERCENT: '% Phòng Thủ', SPD_PERCENT: '% Tốc Độ', HP_PERCENT: '% Sinh Lực',
                    CR_PERCENT: '% Tỉ Lệ Chí Mạng', CDMG_PERCENT: '% Sát Thương Chí Mạng',
                    ATK_AMP: '% Tổng Tấn Công', DEF_AMP: '% Tổng Phòng Thủ', SPD_AMP: '% Tổng Tốc Độ', HP_AMP: '% Tổng Sinh Lực',
                    DMG_AMP: '% Khuếch Đại Sát Thương', DMG_RES: '% Chống Chịu Sát Thương', EVASION: '% Né Tránh', SHIELD: 'Khiên',
                    ATK: 'Tấn Công', DEF: 'Phòng Thủ', SPD: 'Tốc Độ', HP: 'Sinh Lực',
                    ATTACK: 'Tấn Công', DEFENSE: 'Phòng Thủ', SPEED: 'Tốc Độ', HEALTH: 'Sinh Lực'
                };


                const changeTexts = changes.split(',').map(change => {
                    const [key, value] = change.split(':');
                    const keyTrimmed = key.trim().toUpperCase();
                    const statName = statMappings[keyTrimmed] || keyTrimmed;
                    const numValue = parseFloat(value);
                    const sign = numValue > 0 ? '+' : '';

                    if (keyTrimmed === 'SHIELD') {
                         return `Tạo ${Math.floor(numValue)} ${statName}`;
                    } else if (keyTrimmed.endsWith('_PERCENT') || keyTrimmed.endsWith('_AMP') || keyTrimmed.endsWith('_RES') || keyTrimmed === 'EVASION' || keyTrimmed === 'CR' || keyTrimmed === 'CDMG') {
                        const percentageValue = Math.round(numValue);
                        return `${sign}${percentageValue}% ${statName.replace('%', '').trim()}`;
                    } else {
                        return `${sign}${numValue} ${statName}`;
                    }
                }).join(', ');
                
                if (duration) {
                     return `${name}: ${changeTexts} trong ${duration} lượt ${targetText}`.trim();
                }
                return `${name}: ${changeTexts} ${targetText}`.trim();
            }
             case 'APPLY_STATUS': {
                const statusName = data.status_id || "Hiệu ứng";
                const duration = data.duration || 1;
                const chance = data.chance ? `${parseFloat(data.chance) * 100}% cơ hội ` : '';
                return `${chance}Gây hiệu ứng ${statusName} trong ${duration} lượt ${targetText}.`.trim();
            }
            default:
                return `Hiệu ứng đặc biệt: ${type}`.trim();
        }
    }).filter(Boolean);

    return effectdescriptions.join(' | ');
};

const DIFFICULTY_MULTIPLIERS = GAME_CONFIG.difficultyMultipliers;
const DIFFICULTY_RANDOMNESS = GAME_CONFIG.difficultyRandomness;

const calculateBalancingBudget = (preliminaryDetails, playerCharacter, gameDifficulty) => {
    if (!preliminaryDetails || !preliminaryDetails.rarity || !preliminaryDetails.category) {
        return 0;
    }

    const { rarity, category } = preliminaryDetails;

    const RARITY_BASE_VALUE = GAME_CONFIG.rarityBaseValue;
    const TYPE_MULTIPLIER = GAME_CONFIG.itemTypeMultiplier;

    const baseValue = RARITY_BASE_VALUE[rarity] || 100;
    const typeMultiplier = TYPE_MULTIPLIER[category] || 1.0;
    const deterministicValue = baseValue * typeMultiplier;
    let [minRange, maxRange] = DIFFICULTY_RANDOMNESS[gameDifficulty] || DIFFICULTY_RANDOMNESS['Thường'];
    if (playerCharacter) {
        const equippedSkills = Object.values(playerCharacter.equippedSkills || {}).filter(Boolean);
        let totalReduction = 0;
        
        equippedSkills.forEach(skill => {
            (skill.passive_effects || []).forEach(effect => {
                if (effect.type === 'REDUCE_BUDGET_RANDOMNESS') {
                    totalReduction += effect.value; // value bây giờ là 10, 20...
                }
            });
        });

        if (totalReduction > 0) {
            const spread = maxRange - minRange;
            const reducedSpread = spread * (1 - Math.min(totalReduction, 100) / 100.0);
            
            const midPoint = (minRange + maxRange) / 2;
            minRange = midPoint - (reducedSpread / 2);
            maxRange = midPoint + (reducedSpread / 2);
        }
    }

    // 3. Tạo ra hệ số ngẫu nhiên cuối cùng trong dải đã được điều chỉnh
    const randomMultiplier = Math.random() * (maxRange - minRange) + minRange;
    const finalBudget = deterministicValue * randomMultiplier;

    return Math.floor(finalBudget);
};

