const useTypewriter = (steps, speed = 40, characterName) => {
    const [displayedText, setDisplayedText] = useState('');
    const [isFinished, setIsFinished] = useState(false);

    const animationFrameIdRef = useRef(null);
    const startTimeRef = useRef(null);
    const totalLengthRef = useRef(0);
    const stepsRef = useRef(steps);

    useEffect(() => {
        stepsRef.current = steps;
        
        let len = 0;
        if (Array.isArray(steps)) {
            steps.forEach(step => {
                len += (step || '').length;
            });
            len += Math.max(0, steps.length - 1); 
        }
        totalLengthRef.current = len;

        startTimeRef.current = null;
        if (animationFrameIdRef.current) {
            cancelAnimationFrame(animationFrameIdRef.current);
        }
        setDisplayedText('');
        setIsFinished(false);
        
        if (steps && steps.length > 0) {
            animationFrameIdRef.current = requestAnimationFrame(animate);
        }

        // Cleanup function để dừng animation khi component unmount
        return () => {
            if (animationFrameIdRef.current) {
                cancelAnimationFrame(animationFrameIdRef.current);
            }
        };
    }, [steps, characterName, speed]); // Thêm speed vào dependency

    const animate = (timestamp) => {
        // Lần đầu tiên chạy, ghi lại thời gian bắt đầu
        if (startTimeRef.current === null) {
            startTimeRef.current = timestamp;
        }

        // Tính toán tổng thời gian đã trôi qua
        const elapsed = timestamp - startTimeRef.current;
        
        // Tính số ký tự LẼ RA phải được hiển thị dựa trên thời gian
        let charsToShow = Math.floor(elapsed / speed);

        // Nếu đã đủ thời gian để hiển thị hết, dừng lại
        if (charsToShow >= totalLengthRef.current) {
            setIsFinished(true);
            
            // Dựng lại chuỗi cuối cùng để đảm bảo nó hoàn chỉnh
            const finalOutput = stepsRef.current.map(step => (step || '').replace(/\[NC\]/g, characterName)).join('\n');
            setDisplayedText(finalOutput);
            
            cancelAnimationFrame(animationFrameIdRef.current);
            return;
        }

        // Dựng lại chuỗi hiển thị dựa trên số ký tự được phép
        let output = '';
        let charsCounted = 0;
        for (const step of stepsRef.current) {
            const stepText = (step || '').replace(/\[NC\]/g, characterName);
            const stepLength = stepText.length;

            if (charsToShow > charsCounted + stepLength) {
                // Nếu dòng này đã gõ xong
                output += stepText + '\n';
                charsCounted += stepLength + 1; // +1 cho ký tự xuống dòng
            } else {
                // Nếu đang gõ dở dòng này
                const charsInThisStep = charsToShow - charsCounted;
                output += stepText.substring(0, charsInThisStep);
                break; // Dừng lại vì đã tìm thấy dòng hiện tại
            }
        }
        
        setDisplayedText(output.trimEnd());
        animationFrameIdRef.current = requestAnimationFrame(animate);
    };

    return [displayedText, isFinished];
};

