const parseStoryWithDialogue = (text) => {
    if (!text || typeof text !== 'string') return [];

    const segments = [];
    let lastIndex = 0;
    // Regex tìm thẻ <dialogue>
    const regex = /<dialogue speaker="([^"]+)">([\s\S]*?)<\/dialogue>/g;
    let match;

    while ((match = regex.exec(text)) !== null) {
        // 1. Lấy phần văn kể chuyện đứng TRƯỚC thẻ dialogue
        if (match.index > lastIndex) {
            const narrativeContent = text.substring(lastIndex, match.index).trim();
            if (narrativeContent) {
                segments.push({
                    type: 'narrative',
                    content: narrativeContent
                });
            }
        }

        // 2. Lấy thông tin từ thẻ dialogue
        segments.push({
            type: 'dialogue',
            speaker: match[1].trim(),
            content: match[2].trim()
        });

        lastIndex = regex.lastIndex;
    }

    // 3. Lấy phần văn kể chuyện còn lại SAU thẻ dialogue cuối cùng
    if (lastIndex < text.length) {
        const remainingContent = text.substring(lastIndex).trim();
        if (remainingContent) {
            segments.push({
                type: 'narrative',
                content: remainingContent
            });
        }
    }

    // Nếu không tìm thấy thẻ dialogue nào, trả về toàn bộ text là narrative
    if (segments.length === 0 && text.trim()) {
        segments.push({ type: 'narrative', content: text.trim() });
    }

    return segments;
};

// --- CẤU HÌNH KẾT NỐI HỆ THỐNG LƯU TRỮ ĐÁM MÂY (0Đ) ---
const SUPABASE_URL = "https://kndbyujqhltmfkryydwh.supabase.co"; 
const SUPABASE_ANON_KEY = "sb_publishable_GjYTTTowUg-P9paHkTvaOg_nW4C3Fye"; 

// 1. Hàm gọi lấy khóa ImgBB bảo mật được giấu trên Supabase
const fetchImgbbKeyFromCloud = async () => {
    try {
        const response = await fetch(`${SUPABASE_URL}/rest/v1/system_config?config_name=eq.imgbb_key&select=config_value`, {
            method: 'GET',
            headers: {
                'apikey': SUPABASE_ANON_KEY,
                'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
            }
        });
        if (!response.ok) {
            throw new Error('Không thể tải cấu hình khóa bảo mật từ Supabase.');
        }
        const data = await response.json();
        if (data && data.length > 0) {
            return data[0].config_value; // Trả về khóa ImgBB dạng chữ thô ở bộ nhớ tạm RAM
        }
        throw new Error('Không tìm thấy khóa cấu hình tương ứng.');
    } catch (error) {
        console.error("Lỗi fetchImgbbKeyFromCloud:", error);
        throw error;
    }
};

// 2. Hàm tải ảnh Base64 lên ImgBB sử dụng khóa lấy động bảo mật
const uploadImageToImgBB = async (imageBase64) => {
    if (!imageBase64 || !imageBase64.startsWith('data:image')) {
        return imageBase64;
    }
    try {
        // Lấy khóa động từ Supabase, khóa này chỉ tồn tại trên RAM, người xem code Canvas sẽ không nhìn thấy
        const activeApiKey = await fetchImgbbKeyFromCloud();

        const cleanBase64 = imageBase64.replace(/^data:image\/\w+;base64,/, "");
        const formData = new URLSearchParams();
        formData.append('image', cleanBase64);

        const response = await fetch(`https://api.imgbb.com/1/upload?key=${activeApiKey}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: formData
        });

        const result = await response.json();
        if (response.ok && result.success) {
            return result.data.url;
        }
        throw new Error(result.error?.message || 'Lỗi tải ảnh lên ImgBB');
    } catch (error) {
        console.error("Lỗi uploadImageToImgBB:", error);
        throw error;
    }
};

// 3. Hàm kiểm tra tính hợp lệ của mã khóa VIP
const verifyVipKeyInCloud = async (keyCode) => {
    if (!keyCode) return null;
    try {
        const response = await fetch(`${SUPABASE_URL}/rest/v1/vip_keys?key_code=ilike.${keyCode.trim()}&select=key_code,status,owner_name`, {
            method: 'GET',
            headers: {
                'apikey': SUPABASE_ANON_KEY,
                'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
            }
        });

        if (!response.ok) {
            throw new Error('Không thể kết nối máy chủ Supabase.');
        }

        const data = await response.json();
        if (!data || data.length === 0) {
            throw new Error('Mã khóa VIP không tồn tại.');
        }

        const keyInfo = data[0];
        if (!keyInfo.status) {
            throw new Error('Mã khóa VIP này đã bị tạm khóa.');
        }

        return {
            isValid: true,
            keyCode: keyInfo.key_code,
            ownerName: keyInfo.owner_name
        };
    } catch (error) {
        console.error("Lỗi verifyVipKeyInCloud:", error);
        throw error;
    }
};

const loadSavesFromCloud = async (keyCode) => {
    try {
        const keyCheck = await verifyVipKeyInCloud(keyCode);
        const canonicalKey = keyCheck.keyCode.trim(); 
        const response = await fetch(`${SUPABASE_URL}/rest/v1/saves?vip_key=eq.${canonicalKey}&select=id,slot_number,metadata,updated_at&order=slot_number.asc`, {
            method: 'GET',
            headers: {
                'apikey': SUPABASE_ANON_KEY,
                'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
            }
        });

        if (!response.ok) {
            const errBody = await response.text();
            console.error("🚨 [LỖI CHI TIẾT SUPABASE]:", errBody);
            throw new Error(`Không thể tải tệp lưu từ máy chủ. Chi tiết lỗi: ${errBody}`);
        }

        const saves = await response.json();
        
        for (const save of saves) {
            if (!save.metadata) {
                console.log(`[Cloud Fallback] Slot ${save.slot_number} lacks metadata. Fetching game_data...`);
                const singleResponse = await fetch(`${SUPABASE_URL}/rest/v1/saves?id=eq.${save.id}&select=game_data`, {
                    method: 'GET',
                    headers: {
                        'apikey': SUPABASE_ANON_KEY,
                        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
                    }
                });
                if (singleResponse.ok) {
                    const singleData = await singleResponse.json();
                    if (singleData && singleData[0]) {
                        save.game_data = singleData[0].game_data;
                    }
                }
            }
        }
        return saves;
    } catch (error) {
        console.error("Lỗi loadSavesFromCloud:", error);
        throw error;
    }
};

const saveGameToCloudDb = async (keyCode, slotNumber, gameData, metadata = null) => {
    try {
        const keyCheck = await verifyVipKeyInCloud(keyCode);
        const canonicalKey = keyCheck.keyCode.trim();

        const checkResponse = await fetch(`${SUPABASE_URL}/rest/v1/saves?vip_key=eq.${canonicalKey}&slot_number=eq.${slotNumber}&select=id`, {
            method: 'GET',
            headers: {
                'apikey': SUPABASE_ANON_KEY,
                'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
            }
        });

        if (!checkResponse.ok) {
            const checkErr = await checkResponse.text();
            console.error("🚨 [LỖI TRUY VẤN KIỂM TRA LƯU]:", checkErr);
            throw new Error(`Kiểm tra tệp lưu thất bại: ${checkErr}`);
        }

        const existingRecords = await checkResponse.json();
        let saveResponse;

        if (existingRecords && existingRecords.length > 0) {
            const recordId = existingRecords[0].id;
            saveResponse = await fetch(`${SUPABASE_URL}/rest/v1/saves?id=eq.${recordId}`, {
                method: 'PATCH',
                headers: {
                    'apikey': SUPABASE_ANON_KEY,
                    'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    game_data: gameData,
                    metadata: metadata,
                    updated_at: new Date().toISOString()
                })
            });
        } else {
            saveResponse = await fetch(`${SUPABASE_URL}/rest/v1/saves`, {
                method: 'POST',
                headers: {
                    'apikey': SUPABASE_ANON_KEY,
                    'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    vip_key: canonicalKey,
                    slot_number: slotNumber,
                    game_data: gameData,
                    metadata: metadata,
                    updated_at: new Date().toISOString()
                })
            });
        }

        if (!saveResponse.ok) {
            const errText = await saveResponse.text();
            console.error("🚨 [LỖI ĐỒNG BỘ CHI TIẾT]:", errText);
            throw new Error(`Không thể đồng bộ tệp lưu lên cơ sở dữ liệu. Chi tiết từ máy chủ: ${errText}`);
        }

        return true;
    } catch (error) {
        console.error("Lỗi saveGameToCloudDb:", error);
        throw error;
    }
};

const fetchFullSaveFromCloud = async (rowId) => {
    const response = await fetch(`${SUPABASE_URL}/rest/v1/saves?id=eq.${rowId}&select=game_data`, {
        method: 'GET',
        headers: {
            'apikey': SUPABASE_ANON_KEY,
            'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
        }
    });
    if (!response.ok) {
        throw new Error("Không thể tải tệp lưu chi tiết từ máy chủ đám mây.");
    }
    const data = await response.json();
    if (data && data[0]) {
        return data[0].game_data;
    }
    throw new Error("Không tìm thấy dữ liệu tệp lưu.");
};

