const formatTimeOfDay = (hour) => {
    let period = '';
    let displayHour = hour;

    if (hour >= 0 && hour < 5) {
        period = "Đêm khuya";
    } else if (hour >= 5 && hour < 12) {
        period = "Sáng";
    } else if (hour >= 12 && hour < 18) {
        period = "Chiều";
        if (hour > 12) displayHour = hour - 12;
    } else {
        period = "Tối";
        if (hour > 12) displayHour = hour - 12;
    }
    
    if (displayHour === 0) displayHour = 12; // 0h là 12h đêm

    return `${displayHour} giờ ${period}`;
};

const applyTimeUpdate = (currentKnowledge, timeUpdateData) => {
    let newKnowledge = JSON.parse(JSON.stringify(currentKnowledge));

    if (!timeUpdateData) return { updatedKnowledge: newKnowledge, failedQuests: [], expiredBuffs: [] };
    if (!newKnowledge.time) newKnowledge.time = { year: 0, month: 1, day: 1, hour: 8 };
    if (!newKnowledge.adventureSkillCooldowns) newKnowledge.adventureSkillCooldowns = {};

    const oldTime = { ...newKnowledge.time };

    let { year, month, day, hour } = newKnowledge.time;
    hour += timeUpdateData.hours || 0;
    day += timeUpdateData.days || 0;
    month += timeUpdateData.months || 0;
    year += timeUpdateData.years || 0;
    
    while (hour >= 24) { hour -= 24; day += 1; }
    while (day > 30) { day -= 30; month += 1; }
    while (month > 12) { month -= 12; year += 1; }
    
    const finalTime = { year, month, day, hour: Math.floor(hour) };
    newKnowledge.time = finalTime;
    
    if (timeUpdateData.weather) {
        newKnowledge.weather = timeUpdateData.weather;
    }
    
    const daysPassed = (finalTime.year - oldTime.year) * 360 + (finalTime.month - oldTime.month) * 30 + (finalTime.day - oldTime.day);

    const failedQuests = [];
    const expiredBuffs = [];

    newKnowledge.characters.forEach(char => {
        if (!char.isPermanentlyDead && char.longTermStatuses) {
            char.longTermStatuses = char.longTermStatuses.filter(status => {
                if (status.type === 'adventure_buff' && status.expiresAt) {
                    if (isTimeAfter(finalTime, status.expiresAt)) {
                        expiredBuffs.push({ characterName: char.Name, buffName: status.name });
                        return false;
                    }
                }
                return true;
            });

            if (daysPassed > 0) {
                let dailyHpLoss = 0;
                char.longTermStatuses.forEach(status => {
                    const template = LONG_TERM_STATUS_TEMPLATES[status.status_id] || status;
                    if (template.effects_per_day?.hp_percent_loss) {
                        dailyHpLoss += char.maxhp * template.effects_per_day.hp_percent_loss;
                    }
                });

                if (dailyHpLoss > 0) {
                    char.hp -= Math.floor(dailyHpLoss * daysPassed);
                }
            }
        }
    });

    if (newKnowledge.quests && Array.isArray(newKnowledge.quests)) {
        const FIVE_DAYS_IN_HOURS = 5 * 24;
        const currentTimeInHours = finalTime.year * 8640 + finalTime.month * 720 + finalTime.day * 24 + finalTime.hour;

        newKnowledge.quests = newKnowledge.quests.filter(quest => {
            // Logic 1: Kiểm tra hết hạn
            if (quest.status === 'active' && quest.expiresAt) {
                if (isTimeAfter(finalTime, quest.expiresAt)) {
                    quest.status = 'failed';
                    failedQuests.push(quest.title);
                }
            }
            
            // Logic 2: Dọn dẹp nhiệm vụ cũ
            if (quest.status === 'completed' || quest.status === 'failed') {
                if (!quest.completedAt) {
                    quest.completedAt = { ...finalTime }; // Ghi lại thời điểm kết thúc nếu chưa có
                }
                const completedAtInHours = quest.completedAt.year * 8640 + quest.completedAt.month * 720 + quest.completedAt.day * 24 + quest.completedAt.hour;
                const hoursSinceCompletion = currentTimeInHours - completedAtInHours;
                
                if (hoursSinceCompletion > FIVE_DAYS_IN_HOURS) {
                    return false;
                }
            }

            return true; 
        });
    }

    if (newKnowledge.loreQuests && Array.isArray(newKnowledge.loreQuests)) {
            const currentTimeInHours = finalTime.year * 8640 + finalTime.month * 720 + finalTime.day * 24 + finalTime.hour;
            const fourteenDaysInHours = 336; 

            newKnowledge.loreQuests = newKnowledge.loreQuests.filter(quest => {
                if (!quest.createdAt) return true;
                const createdAtInHours = (quest.createdAt.year || 0) * 8640 + (quest.createdAt.month || 1) * 720 + (quest.createdAt.day || 1) * 24 + (quest.createdAt.hour || 0);
                const hoursElapsed = currentTimeInHours - createdAtInHours;
                return hoursElapsed <= fourteenDaysInHours;
            });
        }

    return { updatedKnowledge: newKnowledge, failedQuests, expiredBuffs };
};


