const runAPI3StateMonitor = async (currentStoryText, currentKnowledge, retries = 3, delay = 3000) => {
    if (gameMode !== 'EXPLORATION' || !currentKnowledge.stateHistory || currentKnowledge.stateHistory.length === 0) return;
    const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";
    const stateHistoryData = currentKnowledge.stateHistory;
    
    const player = currentKnowledge.characters.find(c => c.isPlayer);
    const activeDebuffs = (player?.longTermStatuses || [])
        .filter(s => {
            const sType = (s.type || s.status_type || "neutral").toLowerCase();
            return sType.includes("debuff") || sType.includes("injury") || sType.includes("adventure_debuff");
        })
        .map(s => s.name || s.status_id)
        .filter(Boolean)
        .join(', ');

    const debuffContext = activeDebuffs ? `\n      * CẢNH BÁO TỐI CAO TỪ HỆ THỐNG: Ký chủ HIỆN ĐANG BỊ CÁC TRẠNG THÁI BẤT LỢI SAU: [${activeDebuffs}]. Hãy đọc thật kỹ cốt truyện Lượt T, nếu thấy bất kỳ dấu hiệu nào cho thấy ký chủ "đã ổn định", "được thanh lọc", "đã chữa trị", "vết thương lành lại" hoặc triệu chứng thuyên giảm, NGƯƠI BẮT BUỘC PHẢI XUẤT THẺ LỆNH GIẢI TRỪ TRẠNG THÁI TƯƠNG ỨNG ĐÓ!` : "";
    const activeQuests = (currentKnowledge.quests || []).filter(q => q.status === 'active');
    const activeQuestsStr = activeQuests.length > 0
        ? activeQuests.map(q => `- Tên: "${q.title}" (ID mục tiêu: ${q.objectives?.map(o => o.id).join(', ')})`).join('\n')
        : "Không có nhiệm vụ nào đang nhận.";

    const prompt = `
VAI TRÒ: Ngươi là Hệ thống Giám sát Thực tại và Trao Thưởng Kỳ Ngộ (API 3) ngầm của game RPG.
NHIỆM VỤ: Đọc câu chuyện thám hiểm vừa xảy ra ở Lượt T và so sánh thông số trạng thái của 2 lượt trước (T-2, T-1) để phán quyết xem câu chuyện vừa rồi có gây ra các biến động vật lý hoặc môi trường bị động nào cho thế giới, đồng thời đánh giá nỗ lực của Ký chủ để tự động trao thưởng Điểm Kỳ Ngộ (EP) nếu xứng đáng.

QUY TẮC PHÁN QUYẾT:
1.  **Cập nhật Thời gian & Thời tiết (TÍNH TOÁN DELTA KHÔNG LÙI BƯỚC):**
    - Đọc kỹ câu kể ở Lượt T để nhận diện mốc thời gian mới (Ví dụ: "Hoàng hôn", "Sáng sớm hôm sau").
    - Quy đổi mốc thời gian đó thành mốc giờ 24h thực tế (H_mới): Sáng sớm=5, Buổi sáng=9, Giữa trưa=12, Chiều=15, Hoàng hôn=18, Tối=21, Nửa đêm=0.
    - Lấy mốc giờ của lượt cũ T-1 (H_cũ) được cung cấp bên dưới.
    - **ÁP DỤNG CÔNG THỨC TOÁN HỌC ĐỂ TÍNH SỐ GIỜ TRÔI QUA (Delta):**
      * Nếu thời gian trôi qua trong cùng một ngày (H_mới >= H_cũ): Delta = H_mới - H_cũ.
      * Nếu thời gian trôi qua xuyên sang ngày hôm sau (H_mới < H_cũ): Delta = (24 - H_cũ) + H_mới.
      * Nếu hành động có khoảng lặng cụ thể (Ví dụ "ngủ 8 tiếng"): Dùng thẳng con số đó làm Delta.
    - Được phép dùng số thập phân (0.25, 0.5) cho các hành động trôi qua vài chục phút.
    - TUYỆT ĐỐI KHÔNG xuất số giờ Delta bằng 0 hoặc số âm.
    - Xuất thẻ lệnh: [TIME_PASSED: hours=X, weather="..."] (X là số Delta vừa tính được).
    - Phân biệt Thời tiết và Đồng hồ: Nếu trời tối đen do "bão ma năng", chỉ cập nhật weather="Bão ma năng", KHÔNG vặn giờ về ban đêm!
2.  **Cập nhật Vị trí Địa lý:**
    - So sánh vị trí ở T-1 với diễn biến ở T. Nếu truyện mô tả nhân vật đã di chuyển đến một nơi chốn mới (ví dụ: "ngươi bước vào quán trọ", "đứng trước hang động"), hãy cập nhật vị trí.
    - Xuất thẻ lệnh: [MOVE_PLAYER: locationName="Tên địa điểm mới"]
3.  **Cập nhật Trạng thái & Sức khỏe (Bao gồm cả giải trừ trạng thái và HỒI PHỤC HP):**
    - Nếu truyện kể nhân vật bị dầm mưa, dính độc, kiệt sức, đói khát, tẩu hỏa nhập ma, hoặc bị thương thâm mạch... hãy dán trạng thái bất lợi dài hạn tương ứng lên cơ thể họ.
      Xuất thẻ lệnh: [APPLY_LONG_TERM_STATUS: target="Ngươi hoặc Tên đồng hành", status_id="BAT_TINH/TRONG_THUONG/XUAT_HUYET/TRUNG_DOC"]
    - Nếu có nhân vật tử vong trong cốt truyện thám hiểm dã ngoại, xuất thẻ: [CHARACTER_DEATH: Name="Tên nhân vật"]
    - ĐẶC BIỆT QUAN TRỌNG: Hãy đối chiếu với các trạng thái hiện có của nhân vật. NẾU câu chuyện miêu tả nhân vật được chữa trị, giải độc, thanh lọc, phục hồi, tỉnh táo lại hoặc trạng thái xấu đã biến mất (ví dụ: "chân nguyên ổn định", "độc đã giải", "hết hỗn loạn"), ngươi BẮT BUỘC phải gỡ bỏ trạng thái tiêu cực đó! ${debuffContext}
      Xuất thẻ lệnh: [CHARACTER_UPDATE: Name="Ngươi hoặc Tên đồng hành", Stats="longtermstatuses:-'Tên chính xác của trạng thái'"] (Ví dụ: [CHARACTER_UPDATE: Name="Ngươi", Stats="longtermstatuses:-'Trọng Thương'"])
    - **CƠ CHẾ PHỤC HỒI HP (MỚI):** NẾU cốt truyện miêu tả Ký chủ nghỉ ngơi (ngủ một giấc, nghỉ chân), vận công điều tức chữa thương, được y sư trị liệu, hoặc dùng bữa ăn no nê hồi phục thể lực, ngươi BẮT BUỘC phải đánh giá mức độ phục hồi và xuất thẻ lệnh hồi HP.
      Xuất thẻ lệnh: [HEAL_PARTICIPANTS: percentage=X] 
      (Trong đó X là số từ 10 đến 100. Ví dụ: Nghỉ ngơi ngắn/ăn nhẹ X=20; Vận công chữa thương tốt X=50; Ngủ một giấc dài qua đêm/được thần y cứu X=100).
4.  **Cập nhật Tiến độ Nhiệm vụ (CẤM BỊA ĐẶT):**
    - DANH SÁCH NHIỆM VỤ ĐANG LÀM: 
      ${activeQuestsStr}
    - ĐỐI CHIẾU NGHIÊM NGẶT: Chỉ được phép cập nhật các nhiệm vụ CÓ MẶT trong danh sách trên. TUYỆT ĐỐI KHÔNG TỰ BỊA RA TÊN NHIỆM VỤ MỚI CHƯA TỒN TẠI!
    - Nếu có tiến triển với nhiệm vụ trong danh sách, xuất thẻ: [QUEST_OBJECTIVE_COMPLETED: questTitle="Tên nhiệm vụ", objectiveId="id_muc_tieu", quantity=X] (X là số lượng vừa hoàn thành thêm).
    - Nếu toàn bộ các mục tiêu của nhiệm vụ đã được hoàn thành đầy đủ, hãy chuyển đổi trạng thái nhiệm vụ sang sẵn sàng trả bằng cách xuất thẻ: [QUEST_UPDATED: title="Tên nhiệm vụ", status="ready_to_turn_in"]
5.  **TÍNH TOÁN KỲ NGỘ & TRAO THƯỞNG EP (QUY TẮC BẮT BUỘC):**
    - Đọc thật kỹ diễn biến hành trình vừa được kể trong Lượt T.
    - Nếu Ký chủ thực hiện các hành động rèn luyện cốt lõi (như giao tranh dã ngoại thắng lợi, bế quan tu luyện chân khí, thiền định, chế đan, luyện khí, hấp thụ linh thảo/đan dược/bí tịch, hoặc nỗ lực giải quyết hiểm họa rủi ro thành công), ngươi BẮT BUỘC phải chấm điểm 'ep_score' dựa trên 4 tiêu chí nghiêm ngặt sau (Tổng điểm tối đa là 100):
      1) Tầm Quan Trọng & Tu Luyện (Cơ bản: từ 0 đến 55 điểm):
         + Thấp (0-5 điểm): Chỉ đơn thuần thám hiểm, đi lại, quan sát cảnh vật hoặc trò chuyện xã giao vô thưởng vô phạt.
         + Trung bình (10-30 điểm): Thu thập nguyên liệu, đánh thắng quái thú thường, bồi dưỡng kỹ thuật dã ngoại cơ bản.
         + Cao (35-55 điểm): Hoàn thành đại nhiệm vụ, bế quan bứt phá cấp độ/đại cảnh giới, chế đan luyện khí cao cấp, hấp thụ thần binh dị bảo.
      2) Mức Độ Rủi Ro (Cơ bản: từ 0 đến 15 điểm):
         + Thấp (0 điểm): Hành vi dã ngoại hoàn toàn an toàn, bình ổn.
         + Trung bình (1-9 điểm): Có rủi ro bị thương ngoài da, hao tổn tài sản vừa phải hoặc nguy cơ bị phục kích.
         + Cao (10-15 điểm): Đối mặt tử lộ cực kỳ nguy hiểm, đặt cược mạng sống, đấu trí cường lực với địch nhân mạnh hơn.
      3) Độ Sáng Tạo (Cơ bản: từ 0 đến 10 điểm):
         + Thấp (0-2 điểm): Ký chủ chỉ lựa chọn thụ động các phương án gợi ý có sẵn.
         + Trung bình (3-7 điểm): Ký chủ tự miêu tả hành động tự do hợp lý, logic.
         + Cao (8-10 điểm): Hành động tự viết cực kỳ đột phá, mưu mẹo, bất ngờ vượt ngoài tầm suy đoán thông thường.
      4) Nhập Vai / Phù Hợp (Cơ bản: từ 0 đến 15 điểm):
         + Thấp (0-3 điểm): Hành vi đi ngược bản sắc tính cách hoặc thân phận đã định hình của nhân vật.
         + Trung bình (4-9 điểm): Nhập vai bình thường.
         + Cao (10-15 điểm): Hành động thể hiện xuất sắc và sâu sắc bản sắc tâm lý của nhân vật.

    - CÔNG THỨC CHẤM: ep_score = (Quan Trọng) + (Rủi Ro) + (Sáng Tạo) + (Phù Hợp)
      [ENCOUNTER_REWARD: ep_score=X, reason="Ghi lý do dâng hiến súc tích bằng tiếng Việt", target="Ngươi" hoặc "Cả đội"]
      *(Dùng target="Cả đội" khi có đồng hành tham gia hỗ trợ hoặc cùng chia sẻ kỳ ngộ)*

    QUY TẮC TRÌNH BÀY:
    - CHỈ trả về các dòng thẻ lệnh dạng [LỆNH: ...], mỗi thẻ trên một dòng riêng biệt.
    - TUYỆT ĐỐI không viết thêm bất kỳ lời dẫn, lời chào, lời giải thích hay lời kể truyện nào ngoài thẻ lệnh! Nếu không có biến động thực tại nào phát sinh, hãy để trống phản hồi.

    --- DỮ LIỆU THÔNG SỐ LƯỢT T-2 ---
    ${JSON.stringify(stateHistoryData[0] || null, null, 2)}

    --- DỮ LIỆU THÔNG SỐ LƯỢT T-1 ---
    ${JSON.stringify(stateHistoryData[1] || null, null, 2)}

    --- TRUYỆN VỪA KỂ (LƯỢT T) ---
    "${currentStoryText}"

    ĐẦU RA THẺ LỆNH HỆ THỐNG:
    `.trim();

    const payload = { contents: [{ role: "user", parts: [{ text: prompt }] }] };
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

    console.log("=========================================");
    console.log("👁️ [API 3 - STATE MONITOR] PROMPT GỬI ĐI:");
    console.log(prompt);
    console.log("=========================================");

    for (let i = 0; i < retries; i++) {
        try {
            const executeMonitorFetch = async () => {
                const response = await fetch(apiUrl, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload)
                });

                if (!response.ok) throw new Error(`HTTP Error ${response.status}`);

                return await response.json();
            };
            const resJson = await globalApiQueue.enqueue(executeMonitorFetch);
            const text = resJson.candidates?.[0]?.content?.parts?.[0]?.text;
            
            console.log("=========================================");
            console.log("👁️ [API 3 - STATE MONITOR] PHẢN HỒI NHẬN VỀ (RAW):");
            console.log(text);
            console.log("=========================================");

            if (text && text.trim() !== '') {
                console.log("⚡ [API 3 ngầm] Khởi chạy cập nhật thực tại thành công:", text);
                const { story, choices: newChoices, updates, commandBlock } = await parseGeminiResponseAndUpdateState(text, currentKnowledge);
                processAndUpdateState(updates, commandBlock, currentKnowledge);
                
                const nextKnowledge = applyUpdates(currentKnowledge, updates, gameMode, commandBlock);
                const isHtabAwakened = nextKnowledge.htab?.isAwakened;
                const isHtabActive = nextKnowledge.systemAssistant?.isActive;
                
                if (isHtabAwakened && gameMode === 'EXPLORATION' && !isHtabActive && !updates.htabAwaken) {
                    const activeSystemQuests = (nextKnowledge.quests || []).filter(q => q.status === 'active' && q.category === 'hệ thống' && q.expiresAt && q.createdAt);
                    
                    let targetQuestToRemind = null;
                    for (const quest of activeSystemQuests) {
                        if (quest.reminderTriggered) continue;
                        
                        const startHours = calculateTimeHours(quest.createdAt);
                        const endHours = calculateTimeHours(quest.expiresAt);
                        const currentHours = calculateTimeHours(nextKnowledge.time);
                        
                        const totalHours = endHours - startHours;
                        const remainingHours = endHours - currentHours;
                        
                        if (totalHours > 0 && remainingHours > 0 && remainingHours <= totalHours * 0.1) {
                            targetQuestToRemind = quest;
                            break;
                        }
                    }

                    if (targetQuestToRemind) {
                        setknowledge(prev => {
                            const newK = JSON.parse(JSON.stringify(prev));
                            const qIdx = newK.quests.findIndex(q => q.id === targetQuestToRemind.id);
                            if (qIdx > -1) {
                                newK.quests[qIdx].reminderTriggered = true;
                            }
                            return newK;
                        });
                        
                        triggerSystemActiveAppearance('quest_reminder', currentStoryText || "", { quest: targetQuestToRemind });
                        return;
                    }
                    return;
                }
                return;
            } else {
                return;
            }
        } catch (e) {
            console.warn(`[API 3 ngầm] Thất bại lần thử thứ ${i + 1} do lỗi mạng:`, e.message);
            if (i < retries - 1) {
                await sleep(delay);
            }
        }
    }
    console.error("[API 3 ngầm] Thất bại hoàn toàn sau tất cả các lần gọi lại thử.");
};


const handleAwakenHtab = async (reason = "MILESTONE_AWAKENING") => {
    if (knowledge.systemAssistant?.isActive) {
        setModalMessage({ show: true, title: 'Hệ Thống Đã Bật', content: 'Hệ thống tối cao đã hoạt động rồi.', type: 'info' });
        return;
    }

    if (knowledge.htab?.isAwakened) {
        if (reason === "DEATH_PRESERVATION") {
            setIsProcessingAction(true);
            const lastStoryItem = storyHistory.filter(item => item.type === 'story').pop()?.content || "Ngươi đang ở giữa hành trình thám hiểm.";
            const lastStoryText = typeof lastStoryItem === 'string' ? lastStoryItem : JSON.stringify(lastStoryItem);
            
            // Sao lưu lựa chọn dã ngoại trước khi gọi cứu mạng
            setBackupChoices(choices);
            setBackupCustomActionInput(customActionInput);
            setCustomActionInput(''); // Xóa rỗng ô nhập để chat với HTAB

            await triggerSystemActiveAppearance('death_preservation', lastStoryText);
        } else {
            setModalMessage({ show: true, title: 'Hệ Thống Đã Thức Tỉnh', content: 'Hệ thống của ngươi vốn đã thức tỉnh từ trước rồi.', type: 'info' });
        }
        return;
    }

    setIsProcessingAction(true);
    setIsHtabAwakening(true);
    setHtabAwakeningSteps([
        "Thế giới đang có sự can thiệp...",
        "Ý niệm liên kết linh hồn đang tiến hành đồng bộ..."
    ]);

    const lastStoryItem = storyHistory.filter(item => item.type === 'story').pop()?.content || "Ngươi đang ở giữa hành trình thám hiểm.";
    const lastStoryText = typeof lastStoryItem === 'string' ? lastStoryItem : JSON.stringify(lastStoryItem);
    const currentPlayerLocation = knowledge.locations.find(loc => loc.id === playerCharacter.current_location_id);
    const locationName = getDisplayName(currentPlayerLocation) || "Nơi Vô Định";

    let reasonContext = "";
    let forcedCommand = "";

    if (reason === "DEATH_PRESERVATION") {
        reasonContext = "Ký chủ vừa cạn kiệt khí huyết, nhận vết thương chí mạng suýt chết, buộc Hệ Thống phải cưỡng chế bộc phát hắc hỏa hộ thể để phong ấn vết thương và bảo vệ đan điền trong ranh giới sinh tử.";
    } else if (reason === "MILESTONE_AWAKENING") {
        reasonContext = "Ký chủ tích lũy đủ nhân quả thâm sâu (đạt cấp độ cao, tích lũy lượng lớn tài sản tiền tệ hoặc đã thám hiểm qua nhiều lượt), khiến linh thức liên kết tự động thức tỉnh.";
        forcedCommand = `[QUEST_ASSIGNED: title="Thử Thách Thức Tỉnh", category="hệ thống", deadline_days=3]`;
    } else {
        reasonContext = "Mệnh lệnh bừng tỉnh tự nhiên từ thiên đạo.";
    }


    const freezePrompt = `
        BỐI CẢNH HIỆN TẠI TRONG TRUYỆN:
        - Địa điểm: ${locationName}
        - Thời gian: ${formatTimeOfDay(knowledge.time.hour)}
        - Thời tiết: ${knowledge.weather}
        - Diễn biến gần nhất: "${lastStoryText.substring(0, 400)}"
        - Lý do bộc phát Hệ Thống: ${reasonContext}

        NHIỆM VỤ: Hãy viết một đoạn văn ngắn (khoảng 5 câu) mô tả cảnh tượng thế giới xung quanh tại địa điểm ${locationName} bỗng nhiên đứng lặng một cách kỳ ảo và huyền bí. Gió đột ngột ngừng thổi, mây ngưng trôi, không gian trở nên tĩnh lặng tuyệt đối. 
        
        QUY TẮC NGÔI KỂ (CỰC KỲ QUAN TRỌNG - BẮT BUỘC):
        - Viết dưới ngôi kể thứ hai, gọi nhân vật chính là "ngươi".
        - TUYỆT ĐỐI không gọi bằng tên riêng "${playerCharacter.Name}" hay dùng các xưng hô thứ ba như "anh/hắn/cậu" trong lời dẫn kể chuyện.
        - Hãy lồng ghép tinh tế lý do bộc phát (${reasonContext}) vào đoạn văn này (Ví dụ: nếu là do cứu mạng, hãy tả cảnh các vết thương chí mạng trên cơ thể ngươi đang đóng băng hoặc được bao phủ bởi ngọn lửa hắc ám kỳ lạ; nếu là tích lũy nhân quả, hãy tả cảnh các luồng linh lực quanh người đang không ngừng cộng hưởng...).
        Không chứa bất kỳ lựa chọn hay thẻ lệnh nào. Chỉ viết văn xuôi tiếng Việt tinh tế, tự nhiên.
    `;

    const playerGender = (playerCharacter.Gender || "Không xác định").toLowerCase();
    const playerGoal = playerCharacter.characterGoal || "Phiêu lưu, tìm kiếm con đường của riêng mình";
    const playerRole = playerCharacter.Role || "Hành Giả";
    const playerBackstory = playerCharacter.Backstory || playerCharacter.characterBackstory || "Vô danh";
    const theme = gameSettings.theme || "Tiên hiệp";

    const recentHistory = (storyHistory || [])
        .filter(h => h && !h.transient && h.summarized !== true)
        .slice(-15)
        .map(h => formatHistoryItemForPrompt(h, 'text_thuong'))
        .join('\n');

    const summariesBlock = (storySummaries || []).length > 0 
        ? storySummaries.map(s => `[Tóm tắt giai đoạn lượt ${s.startTurn || 'đầu'} - ${s.endTurn || '?'}] (Bản ghi cấp ${s.level || 1}):\n${s.content}`).join('\n\n')
        : "Chưa có.";

    const appraisalPrompt = `
        VAI TRÒ: Ngươi là một thực thể tối cao chuyên định hình và kiến tạo "Hệ thống Trợ Lý Ký Sinh" (System Assistant) hoàn hảo cho Ký chủ.
        
        LỊCH SỬ HÀNH TRÌNH ĐÃ QUA CỦA KÝ CHỦ (Hãy sử dụng chi tiết các biến cố, kỳ ngộ, thù hận, đối thủ đã gặp hoặc lựa chọn lớn trong lịch sử này để thiết lập xuất thân, thái độ, tính cách và lời thoại mở đầu của Hệ thống sao cho gắn kết chặt chẽ và sâu sắc nhất với câu chuyện):
        - Tóm tắt biên niên sử:
        ${summariesBlock}

        - Diễn biến chi tiết gần nhất:
        ${recentHistory}

        HỒ SƠ KÝ CHỦ (NHÂN VẬT CHÍNH):
        - Tên: ${playerCharacter.Name}
        - Giới tính: ${playerGender}
        - Vai trò/Thân phận: ${playerRole}
        - Cấp độ hiện tại: ${playerCharacter.level}
        - Tài sản tích lũy: ${playerCharacter.currency} ${gameSettings.currencyName}
        - Tiểu sử: "${playerBackstory.substring(0, 300)}"
        - Mục tiêu cốt lõi: "${playerGoal}"
        
        BỐI CẢNH THỨC TỈNH:
        - Lý do Hệ Thống thức tỉnh ngay lúc này: ${reasonContext}
        
        BỐI CẢNH THẾ GIỚI:
        - Chủ đề: "${theme}"
        - Mô tả chung: "${gameSettings.setting}"

        CHỈ THỊ KIẾN TẠO HỆ THỐNG ĐỘC BẢN:
        Ngươi phải thiết kế một thực thể Hệ Thống ký sinh có xuất thân, tính cách, ngoại hình và giới tính hoàn hảo để hỗ trợ, tương tác hoặc tương khắc với Ký chủ một cách phù hợp và kịch tính nhất dựa trên bối cảnh thế giới và lịch sử hành trình:
        - Thể loại Tiên hiệp/Kiếm hiệp/Cổ trang: Hệ thống có thể là khí linh cổ xưa, kiếm linh thanh tao, tiên tử bị phong ấn hoặc hồn thể của một đại năng tu vi thông thiên. Giọng điệu nho nhã, có thể xưng hô "Ta - Ngươi" hoặc "Bản tôn - Ký chủ".
        - Thể loại Khoa huyễn/Cyberpunk/Hiện đại: Hệ thống nên là một trí tuệ nhân tạo (AI) tối tân, một hologram thông minh hoặc trợ lý cơ giáp. Giọng điệu chuyên nghiệp, máy móc, xưng "Hệ thống - Ký chủ" hoặc mang tính công nghệ cao.
        - Thể loại Ngôn tình/Lãng mạn: Hệ thống nên có ngoại hình và tính cách cuốn hút, xưng hô thân mật, ấm áp hoặc mang nét trêu chọc thú vị.
        - Thể loại Kỳ ảo/Ma thuật/Dungeon: Hệ thống có thể là một linh hồn ma pháp, tiểu tinh linh, quỷ linh khế ước hoặc sứ giả ma pháp tinh nghịch.
        - Các thể loại khác: Tự do sáng tạo phong cách phù hợp nhất.

        Nhiệm vụ: Sáng tạo ra toàn bộ thuộc tính cho hệ thống này bao gồm:
        1. "name": Tên hệ thống phù hợp với thế giới.
        2. "gender": Giới tính (Nam, Nữ, Hoặc Thực thể phi giới tính).
        3. "personality": Tính cách đặc trưng.
        4. "backstory": Tiểu sử nguồn gốc sâu xa của Hệ thống phù hợp với bối cảnh trò chơi và hành trình của Ký chủ.
        5. "appearance": Mô tả chi tiết ngoại hình, vóc dáng, thần thái để làm tư liệu vẽ ảnh.
        6. "initialDialogue": Lời chào mở đầu đầy ấn tượng và lôi cuốn ngay trong thức hải, sử dụng giọng điệu và xưng hô phù hợp hoàn hảo với tính cách của nó và thể loại của câu chuyện. Lời chào này BẮT BUỘC phải có phản ứng trực tiếp liên quan đến lý do Hệ Thống thức tỉnh (${reasonContext}) và phản ánh một số dấu ấn lịch sử đã qua (Ví dụ: nếu là do cứu mạng, Hệ Thống có thể mỉa mai sự yếu kém, trêu chọc việc ngươi suýt chết hoặc than thở vì tốn hao linh lực để giữ mạng cho ngươi; nếu là do ngươi thăng cấp/giàu có, Hệ Thống có thể nhận xét đầy thú vị về tiến độ hoặc số tài sản ngươi đang có...).

        CHỈ trả về một đối tượng JSON duy nhất theo đúng cấu trúc schema.
    `;

    const htabAppraisalSchema = {
        type: "OBJECT",
        properties: {
            name: { type: "STRING" },
            gender: { type: "STRING" },
            personality: { type: "STRING" },
            backstory: { type: "STRING" },
            appearance: { type: "STRING" },
            initialDialogue: { type: "STRING" }
        },
        required: ["name", "gender", "personality", "backstory", "appearance", "initialDialogue"]
    };

    try {
        const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";
        
        // Sao lưu lựa chọn dã ngoại trước khi chạy tác vụ thức tỉnh ngầm
        setBackupChoices(choices);
        setBackupCustomActionInput(customActionInput);
        setCustomActionInput(''); // Xóa rỗng ô nhập để chat với HTAB

        const [freezeNarrative, appraisalRaw] = await Promise.all([
            fetchGenericGeminiText(freezePrompt),
            fetchWithRetries(
                `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`,
                {
                    contents: [{ role: "user", parts: [{ text: appraisalPrompt }] }],
                    generationConfig: { response_mime_type: "application/json", response_schema: htabAppraisalSchema }
                }
            )
        ]);

        if (freezeNarrative) {
            setHtabAwakeningSteps([freezeNarrative]);
        }

        const appraisalData = JSON.parse(appraisalRaw);

        const avatarPrompt = `
            A beautiful, detailed 2D anime portrait of ${appraisalData.name}, framed from the waist up (waist-up portrait showing her entire upper body).
            Theme: ${gameSettings.theme}.
            Gender and details: ${appraisalData.gender}, ${appraisalData.appearance}. 
            CRITICAL COLOR RULES (CHROMA KEY):
            1. The character MUST have a thick PURE #000000 BLACK outline/border around her entire body, hands, and hair.
            2. The ENTIRE background MUST be PURE #FFFFFF WHITE.
            3. DO NOT draw a desk, table, shadows, or any scenery. ONLY draw the character on solid white background.
            2D flat anime illustration style.
        `;
        const rawAiImage = await generateSingleImage(avatarPrompt, effectiveApiKey);
        const baseB64 = await processSystemAssistantSprite(rawAiImage);

        await sleep(3500);

        const systemCharacterObj = {
            id: 'system_assistant',
            isPlayer: false,
            isCompanion: false,
            inParty: false,
            Name: appraisalData.name,
            Gender: appraisalData.gender,
            Role: "Hệ Thống Ký Sinh",
            description: appraisalData.backstory,
            Appearance: appraisalData.appearance,
            Personality: appraisalData.personality,
            Stance: "Cộng Sinh",
            level: 1,
            isAppraised: true,
            avatarStoredLocally: true,
            avatarBase64: baseB64,
            images: {
                base: baseB64,
                idle: baseB64,
                smile: baseB64,
                sad: baseB64,
                angry: baseB64,
                laugh: baseB64,
                skills: {}
            }
        };

        await storeAvatarInIndexedDB('system_assistant', baseB64);
        await storeAvatarInIndexedDB('system_assistant_images', systemCharacterObj.images);

        setknowledge(prev => {
            const newKnowledge = JSON.parse(JSON.stringify(prev));
            
            const filteredChars = (newKnowledge.characters || []).filter(c => c.id !== 'system_assistant');
            newKnowledge.characters = [systemCharacterObj, ...filteredChars];

            newKnowledge.systemAssistant = {
                isActive: true,
                dialogue: appraisalData.initialDialogue,
                expression: "idle",
                images: {
                    base: baseB64,
                    idle: baseB64,
                    smile: baseB64,
                    sad: baseB64,
                    angry: baseB64,
                    laugh: baseB64
                }
            };

            newKnowledge.htab = {
                ...prev.htab,
                isAwakened: true,
                name: appraisalData.name,
                personality: appraisalData.personality,
                origin: appraisalData.backstory,
                energy: prev.htab?.energy !== undefined ? prev.htab.energy : 50,
                currentEnergy: prev.htab?.currentEnergy !== undefined ? prev.htab.currentEnergy : 50,
                affinity: prev.htab?.affinity !== undefined ? prev.htab.affinity : 50,
                avatarBase64: baseB64,
                chatHistory: [{ role: 'system', content: appraisalData.initialDialogue }]
            };

            return newKnowledge;
        });

        setCurrentHtabDialogue(appraisalData.initialDialogue);

        const updateExpressionInBg = async (exprKey, poseDesc) => {
            try {
                const url = await generateSystemAssistantPose(poseDesc, rawAiImage, effectiveApiKey);
                if (url) {
                    const existingImages = await getAvatarFromIndexedDB('system_assistant_images') || {
                        base: baseB64,
                        idle: baseB64,
                        smile: baseB64,
                        sad: baseB64,
                        angry: baseB64,
                        laugh: baseB64,
                        skills: {}
                    };
                    existingImages[exprKey] = url;
                    await storeAvatarInIndexedDB('system_assistant_images', existingImages);

                    setknowledge(prev => {
                        const newK = JSON.parse(JSON.stringify(prev));
                        const sysChar = newK.characters.find(c => c.id === 'system_assistant');
                        if (sysChar) {
                            if (!sysChar.images) sysChar.images = {};
                            sysChar.images[exprKey] = url;
                        }
                        if (newK.systemAssistant) {
                            if (!newK.systemAssistant.images) newK.systemAssistant.images = {};
                            newK.systemAssistant.images[exprKey] = url;
                        }
                        return newK;
                    });
                    console.log(`[Hệ Thống] Đã cập nhật biểu cảm: ${exprKey}`);
                }
            } catch (e) {
                console.warn(`[HTAB Cảnh báo] Tạo biểu cảm ${exprKey} thất bại:`, e.message);
            }
        };

        updateExpressionInBg('smile', "Slightly smiling, gentle friendly smile expression");
        updateExpressionInBg('sad', "Sad, melancholy, downcast expression");
        updateExpressionInBg('angry', "Angry, furious, scowling expression");
        updateExpressionInBg('laugh', "Laughing happily, wide cheerful open-mouth laugh expression");

        setStoryHistory(prev => [...prev, { id: crypto.randomUUID(), type: 'system', content: freezeNarrative }]);
        setIsHtabChatActive(true);
        setCurrentHtabDialogue(appraisalData.initialDialogue);
        setIsHtabAwakening(false);

    } catch (err) {
        console.error("Lỗi kích hoạt HTAB:", err);
        setIsHtabAwakening(false);
    } finally {
        setIsProcessingAction(false);
    }
};


const resumeWorldFromHtab = async (collectedCommands, chatHistory, transitionNarrative, transitionChoices, updates, commandBlock) => {
    setIsProcessingAction(true);
    
    let combinedCommandBlock = commandBlock || "";
    
    setknowledge(prev => {
        const baseKnowledge = {
            ...prev,
            systemAssistant: {
                ...prev.systemAssistant,
                isActive: false,
                dialogue: ""
            }
        };
        
        let finalUpdates = { ...updates };
        collectedCommands.forEach(cmd => {
            let key = cmd.type;
            const parsed = parseKeyValueString(cmd.payload);
            if (key === 'ITEM_IDEA_GAINED') key = 'itemIdeaGained';
            else if (key === 'WORLD_ITEM') key = 'worldItemsToCreate';
            else if (key === 'APPLY_LONG_TERM_STATUS') key = 'longTermStatusesToAdd';
            else if (key === 'QUEST_ASSIGNED') key = 'quests'; 
            else if (key === 'CHARACTER_UPDATE') key = 'characterUpdates';
            // -------------------------------------------------------------------

            if (!finalUpdates[key]) finalUpdates[key] = [];
            finalUpdates[key].push(parsed);
        });

        return applyUpdates(baseKnowledge, finalUpdates, 'EXPLORATION', combinedCommandBlock);
    });

    setIsHtabChatActive(false);
    setCurrentHtabDialogue("");
    setHtabExitPending(false);
    setHtabPendingResumeData(null);

    // Gộp tin nhắn từ biệt (transitionNarrative) vào làm tin nhắn cuối của Thức Hải
    let finalChatHistory = [...(chatHistory || [])];
    if (transitionNarrative) {
        finalChatHistory.push({
            role: 'system',
            content: transitionNarrative
        });
    }

    if (finalChatHistory.length > 0) {
        const htabSessionEntry = {
            id: crypto.randomUUID(),
            type: 'htab_dialogue_session',
            content: finalChatHistory,
            htabName: knowledge.htab?.name || 'Hệ Thống'
        };
        setStoryHistory(prev => [...prev, htabSessionEntry]);
    }

    setCustomActionInput(backupCustomActionInput);
    
    // Khôi phục 4 ô gợi ý hành động, nếu bị trống thì tự động bù đắp bằng mảng dã ngoại mặc định
    setChoices(backupChoices && backupChoices.length > 0 ? backupChoices : [
        "Quan sát xung quanh kỹ hơn. {Tỷ lệ thành công: Tuyệt đối. Hậu quả/Phần thưởng: Có thể phát hiện thêm chi tiết.}",
        "Kiểm tra lại hành trang. {Tỷ lệ thành công: Tuyệt đối. Hậu quả/Phần thưởng: Sắp xếp lại vật phẩm.}",
        "Nghỉ ngơi một lát. {Tỷ lệ thành công: Tuyệt đối. Hậu quả/Phần thưởng: Phục hồi thể lực.}",
        "Tiếp tục hành trình thám hiểm. {Tỷ lệ thành công: Tuyệt đối. Hậu quả/Phần thưởng: Thúc đẩy câu chuyện.}"
    ]);
    
    setIsProcessingAction(false);
};

const handleHtabChat = async (userText) => {
    if (!userText.trim() || isProcessingAction) return;

    const htabObj = knowledge.htab || {};
    const currentLvl = htabObj.level || 1;
    const maxSta = HTAB_MAX_STA[currentLvl] || 100;
    const currentEnergy = htabObj.currentEnergy ?? maxSta;
    const currentExp = htabObj.currentExp || 0;
    const maxExp = HTAB_EXP_LIMITS[currentLvl] || 1000;
    const affinity = htabObj.affinity ?? 50;

    const chatCost = 5;

    if (currentEnergy < chatCost) {
        setModalMessage({ 
            show: true, 
            title: "Cạn Kiệt Năng Lượng", 
            content: "Hệ thống đã cạn kiệt năng lượng dâng hiến (STA < 5). Hãy cung phụng linh khí hoặc ngân lượng để tiếp tục tương tác.", 
            type: "error" 
        });
        return;
    }

    setIsProcessingAction(true);
    setCustomActionInput(''); 

    const updatedHistory = [...(htabObj.chatHistory || []), { role: 'user', content: userText }];
    const nextEnergy = Math.max(0, currentEnergy - chatCost);
    const systemOutOfEnergy = nextEnergy < chatCost;
    
    setknowledge(prev => ({
        ...prev,
        htab: { 
            ...prev.htab, 
            chatHistory: updatedHistory,
            energy: nextEnergy,
            currentEnergy: nextEnergy
        }
    }));

    const energyWarningBlock = systemOutOfEnergy 
        ? `LƯU Ý CỰC KỲ QUAN TRỌNG: Năng lượng dâng hiến của bạn đã cạn kiệt hoàn toàn (${nextEnergy} < 5). Đây là phản hồi CUỐI CÙNG của bạn trước khi sập nguồn ngủ say. Bạn BẮT BUỘC phải nói lời tạm biệt yếu ớt, mệt mỏi, dặn dò hoặc chế giễu ký chủ lần cuối rồi cưỡng chế ngắt kết nối (Hãy chèn thẻ [SYSTEM_LEAVE] ở cuối câu thoại).`
        : `LƯU Ý VỀ NĂNG LƯỢNG: Lượt phản hồi này tiêu hao thêm 5 điểm năng lượng của bạn. Khi năng lượng cạn kiệt, bạn sẽ rơi vào trạng thái ngủ say. Hãy cảnh báo ký chủ nếu năng lượng của bạn đang quá thấp (dưới 15).`;

    try {
        const lastStoryItem = storyHistory.filter(item => item.type === 'story').pop()?.content || "Ngươi đang ở giữa hành trình thám hiểm.";
        const lastStoryText = typeof lastStoryItem === 'string' ? lastStoryItem : JSON.stringify(lastStoryItem);
        
        const reasonContext = "Ký chủ gửi truyền âm liên lạc trong Thức Hải để trò chuyện tiếp nối cuộc đối thoại hiện tại.";
        const htabPrompt = getUnifiedHtabPrompt(lastStoryText, reasonContext, "", updatedHistory, energyWarningBlock, storyHistory, storySummaries, gameSettings, knowledge);

        const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";
        const response = await fetchWithRetries(
            `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`,
            { contents: [{ role: "user", parts: [{ text: htabPrompt }] }] }
        );
        
        if (response) {
            console.log("=== [DEBUG HTAB CHAT] RAW RESPONSE ===");
            console.log(response);
            console.log("======================================");

            let cleanResponse = response;
            let detectedEmotion = 'idle';
            let shouldExit = false;
            let affinityDelta = 0;
            const collectedCommands = [];

            const emotionMatch = response.match(/\[HTAB_EMOTION:\s*type="([^"]+)"\]/i);
            if (emotionMatch) {
                const rawEmo = emotionMatch[1].toLowerCase().trim();
                if (['smile', 'happy', 'teasing', 'talking'].includes(rawEmo)) detectedEmotion = 'smile';
                else if (['sad', 'melancholy'].includes(rawEmo)) detectedEmotion = 'sad';
                else if (['angry', 'furious'].includes(rawEmo)) detectedEmotion = 'angry';
                else if (['laugh', 'joy'].includes(rawEmo)) detectedEmotion = 'laugh';
                else detectedEmotion = 'idle';

                cleanResponse = cleanResponse.replace(/\[HTAB_EMOTION:[^\]]+\]/gi, '');
            }

            console.log(`[DEBUG HTAB] Emotion detected: ${detectedEmotion}`);

            // Cải tiến kiểm tra không phân biệt chữ hoa chữ thường đối với thẻ SYSTEM_LEAVE
            const hasSystemLeaveTag = /\[SYSTEM_LEAVE\]/i.test(response);
            console.log(`[DEBUG HTAB] [SYSTEM_LEAVE] tag in raw response: ${hasSystemLeaveTag}`);
            console.log(`[DEBUG HTAB] systemOutOfEnergy status: ${systemOutOfEnergy}`);

            if (hasSystemLeaveTag || systemOutOfEnergy) {
                shouldExit = true;
                cleanResponse = cleanResponse.replace(/\[SYSTEM_LEAVE\]/gi, '');
                console.log(`[DEBUG HTAB] shouldExit trigger set to TRUE`);
            }

            const tagRegex = /\[([A-Z_]+):\s*([^\]]+)\]/g;
            let match;
            while ((match = tagRegex.exec(response)) !== null) {
                const tagName = match[1];
                const dataString = match[2];
                
                if (tagName === 'AFFINITY_CHANGED') {
                    const parsedAffinity = parseKeyValueString(dataString);
                    const delta = parseInt(parsedAffinity.value, 10);
                    if (!isNaN(delta)) {
                        affinityDelta += delta;
                    }
                    cleanResponse = cleanResponse.replace(match[0], '');
                } else {
                    collectedCommands.push({ type: tagName, payload: dataString });
                    cleanResponse = cleanResponse.replace(match[0], '');
                }
            }
            
            cleanResponse = cleanResponse.trim();
            const updatedHistoryWithSystem = [...updatedHistory, { role: 'system', content: cleanResponse }];

            setknowledge(prev => {
                const newK = JSON.parse(JSON.stringify(prev));
                
                const currentAffinity = prev.htab?.affinity ?? 50;
                const nextAffinity = Math.max(0, Math.min(100, currentAffinity + affinityDelta));

                newK.htab = { 
                    ...newK.htab, 
                    chatHistory: updatedHistoryWithSystem,
                    currentEmotion: detectedEmotion,
                    affinity: nextAffinity,
                    recentDonations: [] 
                };
                
                newK.systemAssistant = {
                    isActive: true,
                    dialogue: cleanResponse,
                    expression: detectedEmotion,
                    images: prev.systemAssistant?.images || {},
                    lastTriggerType: prev.systemAssistant?.lastTriggerType || "casual"
                };

                return newK;
            });
            
            setCurrentHtabDialogue(cleanResponse);

            let currentAccumulated = [...pendingHtabCommands, ...collectedCommands];

            if (shouldExit) {
                console.log(`[DEBUG HTAB] Starting transition process back to world...`);
                let commandSummaryText = [];
                currentAccumulated.forEach(cmd => {
                    if (cmd.type === 'ITEM_IDEA_GAINED' || cmd.type === 'WORLD_ITEM') {
                        const parsed = parseKeyValueString(cmd.payload);
                        commandSummaryText.push(`Nhận được vật phẩm mới: ${parsed.name || parsed.Name}`);
                    } else if (cmd.type === 'APPLY_LONG_TERM_STATUS') {
                        const parsed = parseKeyValueString(cmd.payload);
                        commandSummaryText.push(`Dính trạng thái cơ thể: ${parsed.name || parsed.status_id}`);
                    } else if (cmd.type === 'QUEST_ASSIGNED') {
                        const parsed = parseKeyValueString(cmd.payload);
                        commandSummaryText.push(`Nhận nhiệm vụ hệ thống: ${parsed.title}`);
                    } else if (cmd.type === 'CHARACTER_UPDATE') {
                        commandSummaryText.push(`Thay đổi chỉ số cơ thể: ${cmd.payload}`);
                    }
                });
                const summarySummary = commandSummaryText.join(', ') || "Không có biến động thể chất đáng kể";

                const last10TurnsText = storyHistory
                    .filter(item => !item.transient && item.type === 'story')
                    .slice(-10)
                    .map(item => {
                        if (Array.isArray(item.content)) {
                            return item.content.map(seg => seg.content || "").join("\n");
                        }
                        return String(item.content);
                    })
                    .join('\n---\n');

                const triggerType = knowledge.systemAssistant?.lastTriggerType || "casual";
                const triggerDescriptions = {
                    quest: "Giao nhiệm vụ Hệ thống ",
                    quest_reminder: "Nhắc nhở thời gian nhiệm vụ Hệ thống sắp cạn kiệt",
                    casual: "Giao lưu ngẫu nhiên trong thức hải",
                    death_preservation: "Bộc phát hắc hỏa cứu mạng trong ranh giới sinh tử",
                    level_up: "Hệ thống thăng cấp tu vi khí linh"
                };
                const triggerContext = triggerDescriptions[triggerType] || "Giao tiếp thức hải ngẫu nhiên";

                const backupChoicesText = backupChoices.map((c, i) => `${i + 1}. ${c}`).join('\n');

                const resumePrompt = getHtabResumePrompt(
                    last10TurnsText,
                    backupChoicesText,
                    triggerContext,
                    summarySummary
                );

                const transitionResponse = await fetchWithRetries(
                    `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`,
                    { contents: [{ role: "user", parts: [{ text: resumePrompt }] }] }
                );

                const partingMessage = transitionResponse.replace(/\[[A-Z_]+(?::\s*[^\]]+)?\]/g, "").trim();

                setHtabPendingResumeData({
                    collectedCommands: currentAccumulated,
                    chatHistory: updatedHistoryWithSystem,
                    transitionNarrative: partingMessage, 
                    transitionChoices: [],
                    updates: {},
                    commandBlock: ""
                });
                setHtabExitPending(true);
                setIsProcessingAction(false);
            } else {
                setPendingHtabCommands(currentAccumulated);
                setIsProcessingAction(false);
            }
        }
    } catch (e) {
        console.error("Lỗi giao tiếp HTAB:", e);
        setIsProcessingAction(false);
    }
};

const handleCustomAction = (actionText) => {
    const trimmedAction = actionText.trim();

    if (knowledge.systemAssistant?.isActive) {
        handleHtabChat(trimmedAction);
        setCustomActionInput("");
        return;
    }

    if (isProcessingAction) return;

    const isGodmode = trimmedAction.startsWith('/godmode');
    const isDebug = trimmedAction.startsWith('/debug');

    if (isGodmode || isDebug) {
        if (gameSettings.difficulty !== 'Dễ') {
            setModalMessage({
                show: true,
                title: "Mệnh Lệnh Bị Chặn",
                content: `Hệ thống từ chối thực thi mật lệnh [${isGodmode ? '/godmode' : '/debug'}] ở cấp độ hiện tại.\n\nTính năng này bị vô hiệu hóa ở độ khó Thường, Khó và Ác Mộng. Chỉ cho phép sử dụng ở độ khó "Dễ".`,
                type: "error"
            });
            setCustomActionInput("");
            return;
        }
    }

    if (trimmedAction.startsWith('/godmode')) {
        const commandContent = trimmedAction.substring(8).trim();
        const addRuleRegex = /\[ADD_RULE:\s*content="([^"]+)"\]/i;
        const timePassedRegex = /\[TIME_PASSED:\s*([^\]]+)\]/i;
        
        const addRuleMatch = commandContent.match(addRuleRegex);
        const timePassedMatch = commandContent.match(timePassedRegex);

        if (addRuleMatch && addRuleMatch[1]) {
            const newRule = addRuleMatch[1];
            setknowledge(prev => {
                const newKnowledge = JSON.parse(JSON.stringify(prev));
                if (!newKnowledge.customRules) {
                    newKnowledge.customRules = [];
                }
                newKnowledge.customRules.push(newRule);
                return newKnowledge;
            });
            setModalMessage({ show: true, title: 'Godmode: Đã Thêm Quy Tắc', content: `Quy tắc mới đã được thêm vào thế giới:\n\n"${newRule}"`, type: 'success' });
            setCustomActionInput('');
            return;
        } else if (timePassedMatch && timePassedMatch[1]) {
            const timeData = parseKeyValueString(timePassedMatch[1]);
            const { updatedKnowledge, failedQuests, expiredBuffs } = applyTimeUpdate(knowledge, timeData);
            
            setknowledge(updatedKnowledge);
            
            let messages = [`**[Hệ thống]** Thời gian đã trôi qua.`];
            if (failedQuests.length > 0) {
                messages.push(`Các nhiệm vụ đã thất bại do hết hạn: ${failedQuests.join(', ')}.`);
            }
            if (expiredBuffs.length > 0) {
                expiredBuffs.forEach(buff => messages.push(`Hiệu ứng "${buff.buffName}" trên ${buff.characterName} đã kết thúc.`));
            }
            setStoryHistory(prev => [...prev, { id: crypto.randomUUID(), type: 'system', content: messages.join('\n') }]);
            setModalMessage({ show: true, title: "Godmode: Tua Thời Gian", content: "Thời gian của thế giới đã được thay đổi.", type: 'success' });
            setCustomActionInput('');
            return;
        }
        
        const godCommand = trimmedAction.substring(8).trim(); 
        const processGodmodeCommand = async () => {
            setModalMessage({ show: true, title: 'Godmode Kích Hoạt', content: `Đang gửi mệnh lệnh tối cao đến AI: "${godCommand}"`, type: 'info' });
            const compilerPrompt = `
                **CHẾ ĐỘ BIÊN DỊCH GODMODE**
                VAI TRÒ: Ngươi là một hệ thống thông dịch, nhận mệnh lệnh bằng ngôn ngữ tự nhiên và chuyển đổi nó thành các thẻ lệnh hệ thống.
                MỆNH LỆNH TỪ NGƯỜI DÙNG: "${godCommand}"
                NHIỆM VỤ:
                1.  Phân tích kỹ mệnh lệnh.
                2.  Tạo ra các thẻ lệnh hệ thống phù hợp từ "BỘ LUẬT TỐI THƯỢNG" để thực thi mệnh lệnh đó.
                3.  **HƯỚNG DẪN DÙNG THẺ (CỰC KỲ QUAN TRỌNG):**
                    - Để tạo VẬT PHẨM: Dùng thẻ [ITEM_IDEA_GAINED: name="...", description="...", rarity="..."]
                    - Để tạo KỸ NĂNG: Dùng thẻ [SKILL_IDEA_GAINED: name="...", description="...", target="Ngươi", rarity="..."]
                    *(Về Phẩm chất: Nếu người dùng không chỉ định, PHẢI chọn ngẫu nhiên 1 trong: Thường, Tốt, Hiếm, Cực Phẩm, Siêu Phẩm, Huyền Thoại).*
                    - Để tạo NHÂN VẬT/QUÁI VẬT: Dùng thẻ [WORLD_NPC: name="...", description="...", level=X, stance="Thân thiện/Thù địch/Trung lập", Personality="...", Gender="Nam/Nữ/Khác", sizeCategory=Y] 
                    *(Lưu ý: sizeCategory từ 1 đến 5 đại diện cho: 1=dáng người nhỏ nhắn, 2=dáng người trung bình, 3=dáng cao ráo, 4=dáng to cao vạm vỡ, 5=khổng lồ).*
                    - Để tạo ĐỊA ĐIỂM: Dùng thẻ [WORLD_LOCATION: name="...", description="...", category="...", tier=X, parentLocationId="..."] 
                    - Để thay đổi CẤP ĐỘ nhân vật hoặc người chơi lập tức: Dùng thẻ [SET_LEVEL: target="Tên nhân vật hoặc Ngươi", value=X]
                    - Để thay đổi TIỀN (Ngân Lượng) hoặc chỉ số của ngươi/NPC lập tức: Dùng thẻ [CHARACTER_UPDATE: Name="Ngươi" hoặc "Tên NPC", Stats="currency:+10000" hoặc "hp:+100" hoặc "atk:+5"]. QUAN TRỌNG: Bắt buộc dùng thuộc tính viết hoa 'Name' và đặt giá trị tương ứng là 'Ngươi' hoặc tên chính xác của NPC để thay đổi chỉ số, tuyệt đối không dùng thuộc tính 'target'.
                    - Để GÁN BUFF / DEBUFF (Trạng thái) cho bản thân hoặc NPC: Dùng thẻ [APPLY_LONG_TERM_STATUS: target="Ngươi" hoặc "Tên NPC", name="Tên hiệu ứng", type="buff" hoặc "debuff", description="Mô tả hiệu ứng", duration_hours=240, stats="atk_percent:50,def_percent:-20"] (duration_hours là thời gian tồn tại, stats là chỉ số buff/debuff).
                    - Để XÓA BUFF / DEBUFF: Dùng thẻ [CHARACTER_UPDATE: Name="Ngươi" hoặc "Tên NPC", Stats="longtermstatuses:-'Tên Hiệu Ứng'"]
                    - Để THỨC TỈNH/GỌI DẬY Hệ thống ăn bám ngay lập tức: Dùng thẻ [HTAB_AWAKEN: name="Hệ Thống"]
                    - Để cập nhật CHỈ SỐ/NĂNG LƯỢNG/EXP/HẢO CẢM của Hệ thống (htab): Dùng thẻ [HTAB_UPDATE: Stats="currentEnergy:+50,currentExp:+100,affinity:+10"] hoặc Stats="level:3"
                4.  Sau khi tạo xong tất cả các thẻ lệnh cần thiết, hãy viết một đoạn văn tường thuật ngắn gọn (2-3 câu) mô tả kết quả của mệnh lệnh.
                5.  **QUY TẮC BẢO VỆ CHIẾN ĐẤU (TỐI QUAN TRỌNG):** Nếu mệnh lệnh của người dùng là "tạo quái vật", "đánh nhau", "chiến đấu"... Ngươi chỉ xuất thẻ [WORLD_NPC] và [START_COMBAT: Targets="Tên quái vật vừa tạo"]. **TUYỆT ĐỐI KHÔNG** đính kèm thẻ tạo vật phẩm hay kỹ năng trong cùng lượt này. Đánh nhau xong mới tính tiếp!
                6.  Cuối cùng, tạo ra 4 lựa chọn hành động mới để câu chuyện tiếp tục.
                
                **VÍ DỤ:**
                - Mệnh lệnh: "cho ta buff sức mạnh gấp đôi trong 10 ngày"
                - Phản hồi đúng:
                [APPLY_LONG_TERM_STATUS: target="Ngươi", name="Thần Lực", type="buff", description="Sức mạnh tăng vọt.", duration_hours=240, stats="atk_percent:100"]
                (Đoạn văn tường thuật và 4 lựa chọn)
                ${coreRules}
            `;
            await callGeminiAPI(compilerPrompt, false, {}, undefined, `Lệnh Godmode: ${godCommand}`);
            setCustomActionInput('');
        };

        processGodmodeCommand();

        return;
    }

    if (trimmedAction.startsWith('/debug')) {
        const parts = trimmedAction.split(' ');
        const subCommand = (parts[1] || '').toLowerCase();
        const args = parts.slice(2);
        let commandIsValid = false;

        setknowledge(prevKnowledge => {
            const newKnowledge = JSON.parse(JSON.stringify(prevKnowledge));
            const playerIndex = newKnowledge.characters.findIndex(c => c.isPlayer);
            if (playerIndex === -1) return prevKnowledge;
            
            let player = newKnowledge.characters[playerIndex];

            if (subCommand === 'setlevel' && args.length > 0) {
                const targetLevel = parseInt(args[0], 10);
                if (!isNaN(targetLevel) && targetLevel > 0) {
                    player.level = targetLevel;
                    player.exp = 0; 
                    
                    const totalAp = calculateTotalAP(targetLevel);
                    const spentAp = Object.values(player.allocatedPoints || {}).reduce((sum, points) => sum + points, 0);
                    player.ap = totalAp - spentAp;                    
                    newKnowledge.characters[playerIndex] = calculateFinalStats(player, newKnowledge.characters);

                    commandIsValid = true;
                    setModalMessage({ show: true, title: 'Lệnh Debug', content: `Đã đặt cấp độ thành ${targetLevel}. Số AP hiện tại: ${player.ap}. Chỉ số gốc không đổi.`, type: 'success' });
                }
            } else if (subCommand === 'addexp' && args.length > 0) {
                const expToAdd = parseInt(args[0], 10);
                if (!isNaN(expToAdd)) {
                    player.exp = (player.exp || 0) + expToAdd;
                    const { updatedChar, levelUpMessages } = handleLevelUp(player, newKnowledge.realmProgressionList);
                    newKnowledge.characters[playerIndex] = updatedChar;
                     if (levelUpMessages.length > 0) {
                        setTimeout(() => {
                           const entries = levelUpMessages.map(msg => ({ id: crypto.randomUUID(), type: 'system', content: `**[Hệ thống]** ${msg}`, transient: true }));
                           setStoryHistory(prevHistory => [...prevHistory, ...entries]);
                        }, 100);
                     }
                    commandIsValid = true;
                    setModalMessage({ show: true, title: 'Lệnh Debug', content: `Đã cộng ${expToAdd} EXP.`, type: 'success' });
                }
            } else if (subCommand === 'die') {
                player.hp = 0;
                newKnowledge.characters[playerIndex] = calculateFinalStats(player, newKnowledge.characters, { preserveHp: true });
                commandIsValid = true;
                setModalMessage({ show: true, title: 'Lệnh Debug', content: 'Ký chủ đã tự sát thành công! HP hiện tại là 0. Hãy nhập một hành động bất kỳ ở khung chat để kích hoạt cơ chế thức tỉnh Hệ Thống.', type: 'success' });
            }
            
            return newKnowledge;
        });

        if (commandIsValid) {
            setCustomActionInput('');
        } else {
            setModalMessage({ show: true, title: 'Lệnh Debug Sai', content: `Lệnh debug không hợp lệ. Lệnh có sẵn: setlevel <số>, addexp <số>, suicide`, type: 'error' });
        }
        setIsProcessingAction(false);
        return; 
    }
    processPlayerAction(trimmedAction, 'user_custom_action');
};


// Thêm hàm mới này vào file của bạn
const generateNpcSkillIdea = async (npc, rarity, effectiveApiKey) => {
    const prompt = `
        VAI TRÒ: Bạn là một nhà thiết kế game chuyên nghiệp, BẬC THẦY trong việc sáng tạo các kỹ năng vừa hấp dẫn vừa an toàn, phù hợp với các quy định về nội dung.

        **THÔNG TIN NPC:**
        - Tên: "${npc.Name}"
        - Vai trò/Mô tả: "${npc.Role || npc.description}"
        - Cấp độ: ${npc.level}
        - **Phẩm chất kỹ năng đã được ấn định:** "${rarity}"

        --- QUY TRÌNH SÁNG TẠO (BẮT BUỘC TUÂN THỦ) ---

        1.  **PHÂN TÍCH VAI TRÒ:** Dựa vào Tên và Mô tả, hãy xác định vai trò chiến đấu của NPC (ví dụ: Sát thương chủ lực, Đỡ đòn, Nhanh nhẹn, Hỗ trợ...).

        2.  **QUY TẮC VÀNG (CỰC KỲ QUAN TRỌNG): TRÁNH BỘ LỌC AN TOÀN**
            *   **TUYỆT ĐỐI KHÔNG** tạo các kỹ năng có mô tả bạo lực thể chất một cách trần trụi (ví dụ: cắn xé, moi tim, xé xác...).
            *   **THAY VÀO ĐÓ, BẮT BUỘC** phải hướng sự sáng tạo vào các chủ đề an toàn và kỳ ảo sau:
                -   **Nguyên tố:** Lửa, Băng, Sét, Gió, Đất... (Ví dụ: "Hỏa Nha Kích", "Băng Phong Trảo").
                -   **Năng lượng/Ma thuật:** Năng lượng hắc ám, ánh sáng, linh hồn, năng lượng bí ẩn... (Ví dụ: "Hắc Ám Gào Thét", "Linh Hồn Rên Rỉ").
                -   **Hiệu ứng trạng thái:** Gây sợ hãi, làm chậm, giảm sức mạnh, gây choáng... (Ví dụ: "Tiếng Gầm Uy Hiếp", "Cái Nhìn Tê Liệt").
            *   **VÍ DỤ TỐT:** Cho "Huyết Lang", một kỹ năng tốt là "Huyết Nguyệt Trảm" (âm thanh ma mị, kỳ ảo) thay vì "Cắn Xé Cổ Họng" (quá bạo lực).

        3.  **SÁNG TẠO TÊN & MÔ TẢ:** Dựa trên vai trò và Quy Tắc Vàng, hãy tạo ra một tên (name) và mô tả ngắn gọn (description) cho kỹ năng, đảm bảo sức mạnh của nó phù hợp với phẩm chất "${rarity}".

        **YÊU CẦU ĐẦU RA:** CHỈ trả về một đối tượng JSON duy nhất theo đúng schema.
    `;
    const schema = {
        type: "OBJECT",
        properties: {
            name: { type: "STRING" },
            description: { type: "STRING" }
        },
        required: ["name", "description"]
    };
    const payload = {
        contents: [{ role: "user", parts: [{ text: prompt }] }],
        generationConfig: { response_mime_type: "application/json", response_schema: schema }
    };
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${effectiveApiKey}`;

    try {
        const jsonText = await fetchWithRetries(apiUrl, payload);
        return JSON.parse(jsonText);
    } catch (error) {
        console.error(`Lỗi khi tạo ý tưởng kỹ năng cho ${npc.Name}:`, error);
        throw error;
    }
};

const findSkillFromActionText = (actionText, character, allCombatants) => {
   const lowerActionText = (actionText || '').toLowerCase();

   if (lowerActionText.includes('đánh thường')) {
       const customVfx = character?.basicAttackVfx || {
           vfxType: 'slash',
           moveType: 'dash',
           color: '#e8d3a1',
           vfxCount: 1,
           customImageUrl: null
       };
       return {
           id: 'basic_attack',
           Name: 'Đánh Thường',
           description: 'Một đòn tấn công vật lý cơ bản.',
           skillType: 'combat',
           skillCategory: 'basic',
           cooldown: 0,
           currentCooldown: 0,
           visual_effects: customVfx,
           effects: [
               {
                   action: {
                       type: 'damage',
                       target: { type: 'single_enemy' },
                       visual_effects: customVfx,
                       power_components: [
                           { source_stat: 'ATK', scale_number: 100, based_on: 'caster' }
                       ],
                       special_properties: {
                           can_crit: true
                       }
                   }
               }
           ]
       };
   }
   
   if (lowerActionText.includes('bỏ chạy') || lowerActionText.includes('rời khỏi')) {
       return {
           id: 'flee',
           Name: lowerActionText.includes('rời khỏi') ? 'Rời Khỏi' : 'Bỏ Chạy',
           description: 'Thoát khỏi trận chiến.',
           skillType: 'combat',
           skillCategory: 'utility'
       };
   }

   let skillPool = [];

   if (character.isPlayer || character.isCompanion) {
       skillPool = Object.values(character.equippedSkills || {}).filter(Boolean);
   } else {
       skillPool = [...(character.skills || [])];
   }

   for (const skill of skillPool) {
       if (skill && skill.Name && lowerActionText.includes(skill.Name.toLowerCase())) {
           return skill;
       }
   }
   
   return null;
};



const findTargetFromActionText = (actionText, allCombatants, caster) => {
    const lowerActionText = (actionText || '').toLowerCase();

    // Sắp xếp để tên dài hơn được kiểm tra trước, tránh lỗi "Lão Trương" bị khớp với "Trương"
    const sortedCombatants = [...allCombatants].sort((a, b) => (getDisplayName(b)?.length || 0) - (getDisplayName(a)?.length || 0));

    // 1. Ưu tiên tìm kiếm tên mục tiêu cụ thể
    if (lowerActionText) {
        for (const combatant of sortedCombatants) {
            const combatantName = getDisplayName(combatant);
            if (combatantName && lowerActionText.includes(combatantName.toLowerCase())) {
                return combatant;
            }
        }
        // Thêm logic nhận diện "ngươi"
        if (lowerActionText.includes('ngươi')) {
            return allCombatants.find(c => c.isPlayer);
        }
    }

    // 2. Fallback logic: Nếu không có tên cụ thể, AI có thể muốn tấn công đối thủ
    if (caster) {
        const isCasterPlayerSide = caster.isPlayer || caster.isCompanion;
        // Tìm kẻ địch còn sống đầu tiên
        const firstEnemy = allCombatants.find(c => {
            const isTargetPlayerSide = c.isPlayer || c.isCompanion;
            return c.hp > 0 && isCasterPlayerSide !== isTargetPlayerSide;
        });
        if (firstEnemy) return firstEnemy;
    }

    // 3. Fallback cuối cùng: Nếu không còn kẻ địch, trả về mục tiêu ngẫu nhiên còn sống (trừ bản thân)
    const anyOtherAlive = allCombatants.find(c => c.hp > 0 && c.id !== caster?.id);
    return anyOtherAlive || null;
};

const isLocationOpen = (location, functionType, currentTime) => {
    if (!location || !Array.isArray(location.functions)) {
        // Nếu không có địa điểm hoặc không có mảng functions, mặc định là không có chức năng đó
        return false;
    }
    
    const func = location.functions.find(f => f.type === functionType);
    
    // Nếu không tìm thấy chức năng, nó không khả dụng
    if (!func) {
        return false;
    }
    
    // Nếu chức năng có tồn tại nhưng không có giờ giấc, nó luôn mở
    if (func.opens === undefined || func.closes === undefined) {
        return true;
    }
    
    // Kiểm tra xem giờ hiện tại có nằm trong khoảng mở cửa không
    const currentHour = currentTime.hour;
    return currentHour >= func.opens && currentHour < func.closes;
};

